INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'cfae8d1e-74f1-407a-9b0e-ea88d8774378',
  '00000000-0000-0000-0000-000000000001',
  $escape$Cosmos: Harnessing Polkadot's Parachains with IBC$escape$,
  $escape$Polkadot's relay chain and parachains enable interchain communication via XCM. To integrate Polkadot parachains with Cosmos, use the Inter-Blockchain Communication (IBC) protocol. The Cosmos SDK provides the necessary IBC modules, such as `ibc-transfer` and `ibc-lightclients-polkadot`. When creating a Cosmos chain that interacts with Polkadot parachains, ensure you have the `ibc` CLI installed and configured. Then, use the `ibc-client` to establish a connection with the Polkadot relay chain. To send a message across chains, you can use the `x/cosmos_ibc_transfer` module. For example:
```typescript
const { Chain } = require('@cosmjs/launchpad');
const chain = Chain.fromSeeds(['your_seeds']);
const ibcClient = chain.getIBCClient('polkadotrelaychain');
ibcClient.sendTransfer('your_address', 'asset_denom', 10);
```
$escape$,
